#include <bits/stdc++.h>
using namespace std;
int n,l[30],r[30],root;
void dfs(int x){
    if(!x)
        return;
    cout<<char(x+'a'-1);
    dfs(l[x]);
    dfs(r[x]);
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        string s;
        cin>>s;
        if(i==1)
            root=s[0]-'a'+1;
        if(s[1]!='*')
            l[s[0]-'a'+1]=s[1]-'a'+1;
        if(s[2]!='*')
            r[s[0]-'a'+1]=s[2]-'a'+1;
    }
    dfs(root);
    return 0;
}
